import { SlidersHorizontal } from "lucide-react";
import { useMemo, useState } from "react";
import CategoryTabs from "../components/CategoryTabs";
import ManualCard from "../components/ManualCard";
import SearchInput from "../components/SearchInput";
import type { ManualCategory } from "../data/manuals";
import { manuals } from "../data/manuals";
import { searchManuals } from "../utils/manuals";

type SortMode = "number" | "recent" | "title";

export default function ManualsPage() {
  const [query, setQuery] = useState("");
  const [category, setCategory] = useState<ManualCategory | "all">("all");
  const [sortMode, setSortMode] = useState<SortMode>("number");

  const filteredManuals = useMemo(() => {
    const results = searchManuals(query, category);
    return [...results].sort((a, b) => {
      if (sortMode === "recent") return b.date.localeCompare(a.date) || b.id - a.id;
      if (sortMode === "title") return a.title.localeCompare(b.title, "ko-KR");
      return a.id - b.id;
    });
  }, [query, category, sortMode]);

  return (
    <div className="page-stack">
      <section className="page-header">
        <span className="eyebrow">Manuals</span>
        <h1>전체 기술 매뉴얼</h1>
        <p>관리 번호 1~17번 기준으로 정리된 캐리마텍 기술 문서 목록입니다.</p>
      </section>

      <section className="filter-panel" aria-label="문서 검색 및 필터">
        <SearchInput value={query} onChange={setQuery} />
        <CategoryTabs value={category} onChange={setCategory} />
        <div className="sort-row">
          <SlidersHorizontal aria-hidden="true" size={18} />
          <label>
            정렬
            <select value={sortMode} onChange={(event) => setSortMode(event.target.value as SortMode)}>
              <option value="number">관리 번호순</option>
              <option value="recent">최근 작성일순</option>
              <option value="title">제목순</option>
            </select>
          </label>
          <span>{filteredManuals.length} / {manuals.length}</span>
        </div>
      </section>

      <section className="manual-grid" aria-live="polite">
        {filteredManuals.map((manual) => (
          <ManualCard key={manual.id} manual={manual} />
        ))}
      </section>
    </div>
  );
}
