import type { ContentBlock, ManualContent } from "../data/manualContents";
import { assetUrl } from "../utils/assets";

type ContentRendererProps = {
  content?: ManualContent;
  title: string;
};

export default function ContentRenderer({ content, title }: ContentRendererProps) {
  if (!content || content.blocks.length === 0) {
    return (
      <section className="empty-content">
        <h2>본문 준비 중</h2>
        <p>원본 변환 결과가 아직 생성되지 않았습니다.</p>
      </section>
    );
  }

  return (
    <article className="manual-content">
      {content.blocks.map((block, index) => renderBlock(block, index, title))}
    </article>
  );
}

function renderBlock(block: ContentBlock, index: number, title: string) {
  switch (block.type) {
    case "heading": {
      const HeadingTag = `h${block.level}` as "h2" | "h3" | "h4";
      return (
        <HeadingTag key={`${block.id}-${index}`} id={block.id}>
          {block.text}
        </HeadingTag>
      );
    }
    case "paragraph":
      return <p key={index}>{block.text}</p>;
    case "formula":
      return (
        <p key={index} className="formula-line">
          {block.text}
        </p>
      );
    case "callout":
      return (
        <aside key={index} className={`callout ${block.tone}`}>
          {block.text}
        </aside>
      );
    case "table":
      return (
        <div key={index} className="table-wrap">
          <table>
            <tbody>
              {block.rows.map((row, rowIndex) => (
                <tr key={rowIndex}>
                  {row.map((cell, cellIndex) =>
                    rowIndex === 0 ? (
                      <th key={cellIndex}>{cell}</th>
                    ) : (
                      <td key={cellIndex}>{cell}</td>
                    )
                  )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      );
    case "image":
      return (
        <figure key={`${block.path}-${index}`} className="content-image">
          <img src={assetUrl(block.path)} alt={block.alt || `${title} 시각 자료`} loading="eager" />
          <figcaption>{block.fileName}</figcaption>
        </figure>
      );
    case "slide":
      const label = block.label || "슬라이드";
      return (
        <section key={`slide-${block.slideNumber}-${index}`} id={`slide-${block.slideNumber}`} className="slide-block">
          {block.imagePath ? (
            <figure className="slide-image">
              <img src={assetUrl(block.imagePath)} alt={block.imageAlt || `${title} ${label} ${block.slideNumber}`} />
            </figure>
          ) : (
            <div className="slide-fallback">
              <strong>
                {label} {block.slideNumber}
              </strong>
              <span>{block.title}</span>
            </div>
          )}
          {block.gifs?.length ? (
            <div className="slide-gifs">
              {block.gifs.map((gif) => (
                <figure key={gif.path} className="content-image">
                  <img src={assetUrl(gif.path)} alt={gif.alt || `${title} GIF`} loading="eager" />
                  <figcaption>{gif.fileName}</figcaption>
                </figure>
              ))}
            </div>
          ) : null}
        </section>
      );
    case "reference":
      return (
        <p key={index} className="reference-line">
          {block.text}
        </p>
      );
    default:
      return null;
  }
}
