import React from "react";
import ReactDOM from "react-dom/client";
import { BrowserRouter, HashRouter } from "react-router-dom";
import App from "./App";
import "./styles/global.css";

const isOfflineBuild = import.meta.env.VITE_OFFLINE === "true";
const baseUrl = import.meta.env.BASE_URL;
const useHashRouter = isOfflineBuild || baseUrl === "./" || window.location.protocol === "file:";
const basename = baseUrl.startsWith("/") ? baseUrl.replace(/\/$/, "") : "";
const redirectUrl = sessionStorage.getItem("carimatec-pages-redirect");

if (redirectUrl) {
  sessionStorage.removeItem("carimatec-pages-redirect");
  const target = new URL(redirectUrl);
  history.replaceState(null, "", `${target.pathname}${target.search}${target.hash}`);
}

ReactDOM.createRoot(document.getElementById("root")!).render(
  <React.StrictMode>
    {useHashRouter ? (
      <HashRouter>
        <App />
      </HashRouter>
    ) : (
      <BrowserRouter basename={basename}>
        <App />
      </BrowserRouter>
    )}
  </React.StrictMode>
);
