import {
  ArrowRight,
  BookOpen,
  CalendarDays,
  Droplets,
  FolderOpen,
  Layers3,
  LibraryBig,
  Search,
  ShieldCheck,
  SlidersHorizontal,
  Sparkles,
} from "lucide-react";
import { useMemo, useState, type CSSProperties } from "react";
import { Link } from "react-router-dom";
import ManualCard from "../components/ManualCard";
import { categories, getManualCountByCategory, libraryMeta, manuals } from "../data/manuals";
import { assetUrl } from "../utils/assets";
import { getFeaturedManuals, getRecentManuals, searchManuals } from "../utils/manuals";

const LAST_UPDATED = libraryMeta.updatedAt;

const coverTags = [
  { label: "출력 품질", icon: Sparkles },
  { label: "서포트", icon: BookOpen },
  { label: "파라미터", icon: SlidersHorizontal },
  { label: "레진 관리", icon: Droplets },
  { label: "내구성", icon: ShieldCheck },
  { label: "문제 해결", icon: Search },
];

export default function HomePage() {
  const [query, setQuery] = useState("");
  const searchResults = useMemo(() => searchManuals(query).slice(0, 6), [query]);
  const featuredManuals = getFeaturedManuals(6);
  const recentManuals = getRecentManuals(5);
  const firstCategorySlug = categories[0]?.slug ?? "";
  const heroStyle = {
    backgroundImage: `url("${assetUrl("assets/brand/academy-cover-background.png")}")`,
  } as CSSProperties;

  return (
    <div className="page-stack">
      <section className="home-hero academy-hero" style={heroStyle} aria-label="CARIMATEC Academy 표지">
        <div className="academy-hero-brand">
          <img src={assetUrl("assets/brand/carimatec-logo-black.png")} alt="carimatec" />
          <span>Academy</span>
        </div>

        <div className="academy-hero-copy">
          <span className="eyebrow">CARIMATEC Academy</span>
          <h1>
            <span>광중합 3D 프린팅</span>
            <span>기술 아카데미</span>
          </h1>
          <p>
            광중합 기반 3D 프린팅의 원리부터 장비 운용, 출력 품질, 소재 활용까지 캐리마텍의 기술 노하우를
            체계적으로 학습할 수 있는 통합 기술 플랫폼입니다.
          </p>
          <div className="hero-actions">
            <Link to="/manuals" className="primary-action">
              문서 목록 보기
              <ArrowRight aria-hidden="true" size={17} />
            </Link>
            <Link to={`/categories/${firstCategorySlug}`} className="secondary-action">
              대분류로 탐색
            </Link>
          </div>
          <label className="academy-hero-search" aria-label="문서 제목, 키워드, 본문 검색">
            <strong>검색</strong>
            <input
              type="search"
              value={query}
              onChange={(event) => setQuery(event.target.value)}
              placeholder="문서 제목, 키워드, 본문 검색"
            />
            <Search aria-hidden="true" size={19} />
          </label>
          {query ? (
            <div className="quick-results academy-hero-results">
              {searchResults.length > 0 ? (
                searchResults.map((manual) => (
                  <Link key={manual.id} to={`/manuals/${manual.slug}`}>
                    <span>No. {String(manual.id).padStart(2, "0")}</span>
                    <strong>{manual.title}</strong>
                    <ArrowRight aria-hidden="true" size={16} />
                  </Link>
                ))
              ) : (
                <p>검색 결과가 없습니다.</p>
              )}
            </div>
          ) : null}
        </div>

        <div className="academy-hero-panel">
          <span className="eyebrow">Technical Library</span>
          <h2>
            <span>Photopolymer</span>
            <span>3D Printing</span>
          </h2>
          <p>Manual Collection</p>
          <div className="academy-metrics" aria-label="라이브러리 요약">
            <div>
              <BookOpen aria-hidden="true" size={20} />
              <strong>{manuals.length}</strong>
              <span>Manuals</span>
            </div>
            <div>
              <FolderOpen aria-hidden="true" size={20} />
              <strong>{categories.length}</strong>
              <span>Topics</span>
            </div>
            <div className="metric-date">
              <CalendarDays aria-hidden="true" size={20} />
              <strong>{LAST_UPDATED}</strong>
              <span>최종 수정일</span>
            </div>
          </div>
          <div className="academy-tags" aria-label="주요 주제">
            {coverTags.map((tag) => {
              const Icon = tag.icon;
              return (
                <span key={tag.label}>
                  <Icon aria-hidden="true" size={14} />
                  {tag.label}
                </span>
              );
            })}
          </div>
        </div>
      </section>

      <section className="stats-band" aria-label="라이브러리 현황">
        <div>
          <LibraryBig aria-hidden="true" size={22} />
          <strong>{manuals.length}</strong>
          <span>전체 문서</span>
        </div>
        <div>
          <Layers3 aria-hidden="true" size={22} />
          <strong>{categories.length}</strong>
          <span>대분류</span>
        </div>
        <div>
          <CalendarDays aria-hidden="true" size={22} />
          <strong>{LAST_UPDATED}</strong>
          <span>최종 수정일</span>
        </div>
      </section>

      <section className="section-block">
        <div className="section-heading">
          <div>
            <span className="eyebrow">Categories</span>
            <h2>대분류</h2>
          </div>
          <Link to="/manuals" className="text-link">
            전체 보기
            <ArrowRight aria-hidden="true" size={17} />
          </Link>
        </div>
        <div className="category-grid">
          {categories.map((category) => (
            <Link
              key={category.slug}
              to={`/categories/${category.slug}`}
              className="category-card"
              style={{ "--category-accent": category.accent } as CSSProperties}
            >
              <span>{getManualCountByCategory(category.name)}개 문서</span>
              <h3>{category.name}</h3>
              <p>{category.description}</p>
            </Link>
          ))}
        </div>
      </section>

      <section className="section-block">
        <div className="section-heading">
          <div>
            <span className="eyebrow">Featured</span>
            <h2>추천 문서</h2>
          </div>
        </div>
        <div className="manual-grid">
          {featuredManuals.map((manual) => (
            <ManualCard key={manual.id} manual={manual} />
          ))}
        </div>
      </section>

      <section className="section-block">
        <div className="section-heading">
          <div>
            <span className="eyebrow">Recent</span>
            <h2>최근 추가 문서</h2>
          </div>
        </div>
        <div className="recent-list">
          {recentManuals.map((manual) => (
            <Link key={manual.id} to={`/manuals/${manual.slug}`}>
              <span>No. {String(manual.id).padStart(2, "0")}</span>
              <strong>{manual.title}</strong>
              <small>{manual.category}</small>
              <ArrowRight aria-hidden="true" size={17} />
            </Link>
          ))}
        </div>
      </section>
    </div>
  );
}
