import type { ContentBlock } from "../data/manualContents";
import { assetUrl } from "../utils/assets";

type TocMode = "text" | "thumbnail";

type TableOfContentsProps = {
  blocks?: ContentBlock[];
  tocMode?: TocMode;
};

type TocEntry = {
  id: string;
  text: string;
  level: 2 | 3 | 4;
};

type ThumbnailEntry = {
  id: string;
  label: string;
  ariaLabel: string;
  imagePath: string;
};

export default function TableOfContents({ blocks = [], tocMode = "text" }: TableOfContentsProps) {
  const thumbnailEntries = collectThumbnailEntries(blocks);

  if (tocMode === "thumbnail" && thumbnailEntries.length > 0) {
    return (
      <nav className="toc-panel" aria-label="문서 목차">
        <h2>목차</h2>
        <ol className="toc-thumbnails">
          {thumbnailEntries.map((entry) => (
            <li key={entry.id}>
              <a href={`#${entry.id}`} className="toc-thumbnail" aria-label={entry.ariaLabel}>
                <img src={assetUrl(entry.imagePath)} alt="" loading="lazy" />
                <span>{entry.label}</span>
              </a>
            </li>
          ))}
        </ol>
      </nav>
    );
  }

  const headings = blocks
    .filter((block): block is Extract<ContentBlock, { type: "heading" }> => block.type === "heading")
    .map((heading) => ({ id: heading.id, text: heading.text, level: heading.level }))
    .filter((heading) => !isGenericPageTitle(heading.text));
  const entries = headings.length > 0 ? headings : collectSlideTextEntries(blocks);

  if (entries.length === 0) {
    return null;
  }

  return (
    <nav className="toc-panel" aria-label="문서 목차">
      <h2>목차</h2>
      <ol>
        {entries.map((entry) => (
          <li key={entry.id} className={`toc-level-${entry.level}`}>
            <a href={`#${entry.id}`}>{entry.text}</a>
          </li>
        ))}
      </ol>
    </nav>
  );
}

function collectSlideTextEntries(blocks: ContentBlock[]): TocEntry[] {
  return blocks
    .filter((block): block is Extract<ContentBlock, { type: "slide" }> => block.type === "slide")
    .map((block) => {
      const fallbackLabel = `${block.label || "슬라이드"} ${block.slideNumber}`;
      return {
        id: `slide-${block.slideNumber}`,
        text: block.title || fallbackLabel,
        level: 2
      };
    });
}

function collectThumbnailEntries(blocks: ContentBlock[]): ThumbnailEntry[] {
  return blocks
    .filter((block): block is Extract<ContentBlock, { type: "slide" }> => block.type === "slide" && Boolean(block.imagePath))
    .map((block) => {
      const fallbackLabel = `${block.label || "페이지"} ${block.slideNumber}`;
      return {
        id: `slide-${block.slideNumber}`,
        label: String(block.slideNumber),
        ariaLabel: block.title || fallbackLabel,
        imagePath: block.imagePath as string
      };
    });
}

function isGenericPageTitle(text: string): boolean {
  return /^(페이지|슬라이드|page|slide)\s*\d+$/i.test(text.trim());
}
