import { categories, featuredManualIds, type Manual, manuals, type ManualCategory } from "../data/manuals";
import { manualContents } from "../data/manualContents";

export function categorySlug(categoryName: ManualCategory): string {
  return categories.find((category) => category.name === categoryName)?.slug ?? "";
}

export function getManualsByCategory(categoryName: ManualCategory): Manual[] {
  return manuals.filter((manual) => manual.category === categoryName);
}

export function getRecentManuals(limit = 5): Manual[] {
  return [...manuals]
    .sort((a, b) => b.date.localeCompare(a.date) || b.id - a.id)
    .slice(0, limit);
}

export function getFeaturedManuals(limit = 6): Manual[] {
  const byId = new Map(manuals.map((manual) => [manual.id, manual]));
  const ordered = featuredManualIds
    .map((manualId) => byId.get(manualId))
    .filter((manual): manual is Manual => Boolean(manual));
  const orderedIds = new Set(ordered.map((manual) => manual.id));
  const fallback = manuals.filter((manual) => manual.featured && !orderedIds.has(manual.id));
  return [...ordered, ...fallback].slice(0, limit);
}

export function getAdjacentManuals(manual: Manual): {
  previous?: Manual;
  next?: Manual;
} {
  const index = manuals.findIndex((candidate) => candidate.id === manual.id);
  return {
    previous: index > 0 ? manuals[index - 1] : undefined,
    next: index >= 0 && index < manuals.length - 1 ? manuals[index + 1] : undefined
  };
}

export function getRelatedManuals(manual: Manual, limit = 4): Manual[] {
  return manuals
    .filter((candidate) => candidate.category === manual.category && candidate.id !== manual.id)
    .slice(0, limit);
}

export function searchManuals(query: string, category: ManualCategory | "all" = "all"): Manual[] {
  const normalizedQuery = query.trim().toLocaleLowerCase("ko-KR");
  return manuals.filter((manual) => {
    const categoryMatch = category === "all" || manual.category === category;
    if (!categoryMatch) return false;
    if (!normalizedQuery) return true;

    const content = manualContents[manual.id]?.searchText ?? "";
    const target = [
      manual.title,
      manual.category,
      manual.summary,
      manual.keywords.join(" "),
      content
    ]
      .join(" ")
      .toLocaleLowerCase("ko-KR");

    return target.includes(normalizedQuery);
  });
}
