import type { ManualCategory } from "../data/manuals";
import { CATEGORY_NAMES } from "../data/manuals";

type CategoryTabsProps = {
  value: ManualCategory | "all";
  onChange: (value: ManualCategory | "all") => void;
};

export default function CategoryTabs({ value, onChange }: CategoryTabsProps) {
  return (
    <div className="segmented-control" role="tablist" aria-label="대분류 필터">
      <button
        type="button"
        className={value === "all" ? "active" : ""}
        onClick={() => onChange("all")}
      >
        전체
      </button>
      {CATEGORY_NAMES.map((category) => (
        <button
          type="button"
          key={category}
          className={value === category ? "active" : ""}
          onClick={() => onChange(category)}
        >
          {category}
        </button>
      ))}
    </div>
  );
}
