import { ArrowLeft } from "lucide-react";
import type { CSSProperties } from "react";
import { Link, useParams } from "react-router-dom";
import ManualCard from "../components/ManualCard";
import { categories, categoriesBySlug, getManualCountByCategory } from "../data/manuals";
import { getManualsByCategory } from "../utils/manuals";

export default function CategoryPage() {
  const { slug } = useParams();
  const category = slug ? categoriesBySlug[slug] : undefined;

  if (!category) {
    return (
      <section className="page-header">
        <span className="eyebrow">Category</span>
        <h1>대분류를 찾을 수 없습니다</h1>
        <Link to="/manuals" className="text-link">
          <ArrowLeft aria-hidden="true" size={17} />
          전체 매뉴얼로 이동
        </Link>
      </section>
    );
  }

  const categoryManuals = getManualsByCategory(category.name);

  return (
    <div className="page-stack">
      <section className="page-header category-header" style={{ "--category-accent": category.accent } as CSSProperties}>
        <Link to="/manuals" className="text-link">
          <ArrowLeft aria-hidden="true" size={17} />
          전체 매뉴얼
        </Link>
        <span className="eyebrow">Category</span>
        <h1>{category.name}</h1>
        <p>{category.description}</p>
        <strong>{categoryManuals.length}개 문서</strong>
      </section>

      <section className="category-switcher" aria-label="대분류 선택">
        <div className="section-heading">
          <div>
            <span className="eyebrow">Browse</span>
            <h2>다른 대분류 보기</h2>
          </div>
        </div>
        <div className="category-switcher-grid">
          {categories.map((item) => (
            <Link
              key={item.slug}
              to={`/categories/${item.slug}`}
              className={item.slug === category.slug ? "category-switcher-link active" : "category-switcher-link"}
              style={{ "--category-accent": item.accent } as CSSProperties}
              aria-current={item.slug === category.slug ? "page" : undefined}
            >
              <span>{getManualCountByCategory(item.name)}개</span>
              <strong>{item.name}</strong>
            </Link>
          ))}
        </div>
      </section>

      <section className="manual-grid">
        {categoryManuals.map((manual) => (
          <ManualCard key={manual.id} manual={manual} />
        ))}
      </section>
    </div>
  );
}
