import { ArrowLeft, ArrowRight, CalendarDays, Download, FileText, UserRound } from "lucide-react";
import { Link, useParams } from "react-router-dom";
import ContentRenderer from "../components/ContentRenderer";
import ManualCard from "../components/ManualCard";
import TableOfContents from "../components/TableOfContents";
import { manualContents } from "../data/manualContents";
import { manualsBySlug } from "../data/manuals";
import { assetUrl } from "../utils/assets";
import { categorySlug, getAdjacentManuals, getRelatedManuals } from "../utils/manuals";

export default function ManualDetailPage() {
  const { slug } = useParams();
  const manual = slug ? manualsBySlug[slug] : undefined;

  if (!manual) {
    return (
      <section className="page-header">
        <span className="eyebrow">Manual</span>
        <h1>문서를 찾을 수 없습니다</h1>
        <Link to="/manuals" className="text-link">
          <ArrowLeft aria-hidden="true" size={17} />
          전체 매뉴얼로 이동
        </Link>
      </section>
    );
  }

  const content = manualContents[manual.id];
  const relatedManuals = getRelatedManuals(manual, 3);
  const adjacent = getAdjacentManuals(manual);

  return (
    <div className="manual-detail">
      <section className="manual-article-header">
        <div className="manual-title-block">
          <Link to="/manuals" className="text-link">
            <ArrowLeft aria-hidden="true" size={17} />
            전체 매뉴얼
          </Link>
          <span className="manual-id">No. {String(manual.id).padStart(2, "0")}</span>
          <h1>{manual.title}</h1>
          <p>{manual.summary}</p>
          <div className="detail-meta">
            <Link to={`/categories/${categorySlug(manual.category)}`} className="category-pill">
              {manual.category}
            </Link>
            <span>
              <UserRound aria-hidden="true" size={16} />
              {manual.author}
            </span>
            <span>
              <FileText aria-hidden="true" size={16} />
              {manual.version}
            </span>
            <span>
              <CalendarDays aria-hidden="true" size={16} />
              {manual.displayDate}
            </span>
          </div>
          {manual.downloadPath ? (
            <a
              className="download-action"
              href={assetUrl(manual.downloadPath)}
              download={manual.downloadFileName || undefined}
            >
              <Download aria-hidden="true" size={17} />
              PDF 다운로드
            </a>
          ) : null}
        </div>
        <img src={assetUrl(manual.coverImage)} alt={`${manual.title} 표지`} className="detail-cover" />
      </section>

      <div className="article-layout">
        <aside className="article-side">
          <TableOfContents blocks={content?.blocks} tocMode={content?.tocMode} />
          {content?.readingMinutes ? (
            <div className="reading-time">
              <span>예상 읽기 시간</span>
              <strong>{content.readingMinutes}분</strong>
            </div>
          ) : null}
        </aside>
        <div className="article-main">
          <ContentRenderer content={content} title={manual.title} />
          <nav className="adjacent-nav" aria-label="이전 다음 문서">
            {adjacent.previous ? (
              <Link to={`/manuals/${adjacent.previous.slug}`}>
                <ArrowLeft aria-hidden="true" size={17} />
                <span>{adjacent.previous.title}</span>
              </Link>
            ) : <span />}
            {adjacent.next ? (
              <Link to={`/manuals/${adjacent.next.slug}`}>
                <span>{adjacent.next.title}</span>
                <ArrowRight aria-hidden="true" size={17} />
              </Link>
            ) : <span />}
          </nav>
        </div>
      </div>

      {relatedManuals.length > 0 ? (
        <section className="section-block related-section">
          <div className="section-heading">
            <div>
              <span className="eyebrow">Related</span>
              <h2>같은 대분류 문서</h2>
            </div>
          </div>
          <div className="manual-grid compact-grid">
            {relatedManuals.map((related) => (
              <ManualCard key={related.id} manual={related} compact />
            ))}
          </div>
        </section>
      ) : null}
    </div>
  );
}
