import { CalendarDays, ChevronRight, Download, FileText } from "lucide-react";
import { Link } from "react-router-dom";
import type { Manual } from "../data/manuals";
import { assetUrl } from "../utils/assets";
import { categorySlug } from "../utils/manuals";

type ManualCardProps = {
  manual: Manual;
  compact?: boolean;
};

export default function ManualCard({ manual, compact = false }: ManualCardProps) {
  return (
    <article className={compact ? "manual-card compact" : "manual-card"}>
      <Link to={`/manuals/${manual.slug}`} className="manual-cover-link" aria-label={manual.title}>
        <img src={assetUrl(manual.coverImage)} alt={`${manual.title} 표지`} className="manual-cover" />
      </Link>
      <div className="manual-card-body">
        <div className="manual-meta-row">
          <span className="manual-id">No. {String(manual.id).padStart(2, "0")}</span>
          <Link to={`/categories/${categorySlug(manual.category)}`} className="category-pill">
            {manual.category}
          </Link>
        </div>
        <h3>
          <Link to={`/manuals/${manual.slug}`}>{manual.title}</Link>
        </h3>
        {!compact ? <p>{manual.summary}</p> : null}
        <div className="manual-facts">
          <span>
            <CalendarDays aria-hidden="true" size={16} />
            {manual.displayDate}
          </span>
          <span>
            <FileText aria-hidden="true" size={16} />
            {manual.version}
          </span>
        </div>
        <div className="manual-card-actions">
          <Link to={`/manuals/${manual.slug}`} className="text-link">
            <span>문서 열기</span>
            <ChevronRight aria-hidden="true" size={17} />
          </Link>
          {manual.downloadPath ? (
            <a
              className="text-link download-link"
              href={assetUrl(manual.downloadPath)}
              download={manual.downloadFileName || undefined}
            >
              <Download aria-hidden="true" size={16} />
              <span>PDF</span>
            </a>
          ) : null}
        </div>
      </div>
    </article>
  );
}
