import { Clock3, FileSearch, Search, SlidersHorizontal, TrendingUp } from "lucide-react";
import { useCallback, useEffect, useMemo, useRef, useState, type FormEvent } from "react";
import CategoryTabs from "../components/CategoryTabs";
import ManualCard from "../components/ManualCard";
import SearchInput from "../components/SearchInput";
import type { ManualCategory } from "../data/manuals";
import { manuals } from "../data/manuals";
import { searchManuals } from "../utils/manuals";

type SortMode = "number" | "recent" | "title";
type SearchHistoryItem = {
  term: string;
  count: number;
  lastSearchedAt: number;
};

const SEARCH_HISTORY_KEY = "carimatec-search-history-v1";

function normalizeSearchTerm(value: string): string {
  return value.trim().replace(/\s+/g, " ");
}

function loadSearchHistory(): SearchHistoryItem[] {
  if (typeof window === "undefined") return [];
  try {
    const parsed = JSON.parse(window.localStorage.getItem(SEARCH_HISTORY_KEY) || "[]");
    if (!Array.isArray(parsed)) return [];
    return parsed
      .filter((item): item is SearchHistoryItem => {
        return (
          item &&
          typeof item.term === "string" &&
          typeof item.count === "number" &&
          typeof item.lastSearchedAt === "number"
        );
      })
      .slice(0, 24);
  } catch {
    return [];
  }
}

function saveSearchHistory(history: SearchHistoryItem[]) {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(SEARCH_HISTORY_KEY, JSON.stringify(history));
  } catch {
    // localStorage may be unavailable in restricted browser modes.
  }
}

export default function SearchPage() {
  const [query, setQuery] = useState("");
  const [category, setCategory] = useState<ManualCategory | "all">("all");
  const [sortMode, setSortMode] = useState<SortMode>("number");
  const [history, setHistory] = useState<SearchHistoryItem[]>([]);
  const lastLoggedTerm = useRef("");

  useEffect(() => {
    setHistory(loadSearchHistory());
  }, []);

  const rememberSearch = useCallback((value: string) => {
    const term = normalizeSearchTerm(value);
    if (term.length < 2) return;

    lastLoggedTerm.current = term;
    setHistory((previous) => {
      const now = Date.now();
      const target = term.toLocaleLowerCase("ko-KR");
      const current = previous.length > 0 ? previous : loadSearchHistory();
      const existing = current.find((item) => item.term.toLocaleLowerCase("ko-KR") === target);
      const next = existing
        ? current.map((item) =>
            item.term.toLocaleLowerCase("ko-KR") === target
              ? { ...item, term, count: item.count + 1, lastSearchedAt: now }
              : item
          )
        : [{ term, count: 1, lastSearchedAt: now }, ...current];
      const compacted = next.sort((a, b) => b.lastSearchedAt - a.lastSearchedAt).slice(0, 24);
      saveSearchHistory(compacted);
      return compacted;
    });
  }, []);

  useEffect(() => {
    const term = normalizeSearchTerm(query);
    if (term.length < 2) return;

    const timeoutId = window.setTimeout(() => {
      if (lastLoggedTerm.current !== term) {
        rememberSearch(term);
      }
    }, 1000);

    return () => window.clearTimeout(timeoutId);
  }, [query, rememberSearch]);

  const searchResults = useMemo(() => {
    const results = searchManuals(query, category);
    return [...results].sort((a, b) => {
      if (sortMode === "recent") return b.date.localeCompare(a.date) || b.id - a.id;
      if (sortMode === "title") return a.title.localeCompare(b.title, "ko-KR");
      return a.id - b.id;
    });
  }, [query, category, sortMode]);

  const recentSearches = useMemo(() => {
    return [...history].sort((a, b) => b.lastSearchedAt - a.lastSearchedAt).slice(0, 6);
  }, [history]);

  const frequentSearches = useMemo(() => {
    return [...history].sort((a, b) => b.count - a.count || b.lastSearchedAt - a.lastSearchedAt).slice(0, 8);
  }, [history]);

  const applyHistoryTerm = (term: string) => {
    setQuery(term);
    rememberSearch(term);
  };

  const clearHistory = () => {
    if (typeof window !== "undefined") {
      window.localStorage.removeItem(SEARCH_HISTORY_KEY);
    }
    lastLoggedTerm.current = "";
    setHistory([]);
  };

  const handleSubmit = (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    rememberSearch(query);
  };

  return (
    <div className="page-stack">
      <section className="page-header search-header">
        <span className="eyebrow">Search</span>
        <h1>통합 검색</h1>
        <p>문서 제목, 키워드, 요약, 본문 내용을 기준으로 캐리마텍 기술 자료를 검색합니다.</p>
      </section>

      <section className="search-console" aria-label="통합 검색">
        <form className="search-command" onSubmit={handleSubmit}>
          <SearchInput value={query} onChange={setQuery} placeholder="문서 제목, 키워드, 본문 검색" />
          <button type="submit" className="primary-action search-submit">
            <Search aria-hidden="true" size={18} />
            검색
          </button>
        </form>
        <div className="search-status">
          <strong>{searchResults.length}개 결과</strong>
          <span>전체 {manuals.length}개 문서 기준</span>
          {query.trim() ? <span>"{normalizeSearchTerm(query)}" 검색 중</span> : <span>검색어 없이 전체 문서를 표시 중입니다</span>}
        </div>

        <div className="search-memory-grid">
          <section className="search-memory-card" aria-label="최근 검색">
            <header>
              <div className="search-memory-title">
                <Clock3 aria-hidden="true" size={18} />
                <h2>최근 검색</h2>
              </div>
              {history.length > 0 ? (
                <button type="button" className="ghost-action" onClick={clearHistory}>
                  기록 지우기
                </button>
              ) : null}
            </header>
            {recentSearches.length > 0 ? (
              <div className="search-chip-list">
                {recentSearches.map((item) => (
                  <button key={`${item.term}-${item.lastSearchedAt}`} type="button" className="search-chip" onClick={() => applyHistoryTerm(item.term)}>
                    {item.term}
                  </button>
                ))}
              </div>
            ) : (
              <p className="search-empty-note">아직 이 브라우저에 저장된 검색어가 없습니다.</p>
            )}
          </section>

          <section className="search-memory-card" aria-label="자주 찾는 키워드">
            <header>
              <div className="search-memory-title">
                <TrendingUp aria-hidden="true" size={18} />
                <h2>자주 찾는 키워드</h2>
              </div>
            </header>
            {frequentSearches.length > 0 ? (
              <div className="search-chip-list">
                {frequentSearches.map((item) => (
                  <button key={item.term} type="button" className="search-chip frequent" onClick={() => applyHistoryTerm(item.term)}>
                    {item.term}
                    <small>{item.count}회</small>
                  </button>
                ))}
              </div>
            ) : (
              <p className="search-empty-note">검색어가 쌓이면 많이 찾은 순서로 표시됩니다.</p>
            )}
          </section>
        </div>
      </section>

      <section className="filter-panel search-filter-panel" aria-label="검색 결과 필터">
        <CategoryTabs value={category} onChange={setCategory} />
        <div className="sort-row">
          <SlidersHorizontal aria-hidden="true" size={18} />
          <label>
            정렬
            <select value={sortMode} onChange={(event) => setSortMode(event.target.value as SortMode)}>
              <option value="number">관리 번호순</option>
              <option value="recent">최근 작성일순</option>
              <option value="title">제목순</option>
            </select>
          </label>
        </div>
      </section>

      {searchResults.length > 0 ? (
        <section className="manual-grid" aria-live="polite">
          {searchResults.map((manual) => (
            <ManualCard key={manual.id} manual={manual} />
          ))}
        </section>
      ) : (
        <section className="empty-results" aria-live="polite">
          <FileSearch aria-hidden="true" size={34} />
          <h2>검색 결과가 없습니다</h2>
          <p>다른 키워드로 검색하거나 대분류 필터를 전체로 변경해 보세요.</p>
        </section>
      )}
    </div>
  );
}
